/**
 * Mortgage glossary terms for /mortgage-glossary/[term].
 * Used for SEO and internal linking. Each term: slug, term, definition, optional explanation/example/relatedGuides/relatedTerms.
 */

export interface GlossaryEntry {
  slug: string;
  term: string;
  definition: string;
  explanation?: string;
  example?: string;
  relatedGuides?: { label: string; href: string }[];
  relatedTerms?: string[]; // slugs
}

const glossary: GlossaryEntry[] = [
  { slug: 'apr', term: 'APR', definition: 'Annual Percentage Rate — the cost of credit expressed as a yearly rate, including interest and certain fees.', explanation: 'APR helps you compare loan offers by showing the total cost per year. It is often higher than the interest rate because it includes fees.', example: 'A loan with a 6.5% interest rate might have an APR of 6.8% after including origination and other fees.', relatedGuides: [{ label: 'What Is APR', href: '/mortgage/what-is-apr' }, { label: 'Mortgage Rate vs APR', href: '/mortgage/mortgage-rate-vs-apr' }], relatedTerms: ['interest-rate', 'loan-estimate', 'closing-disclosure'] },
  { slug: 'dti', term: 'DTI (Debt-to-Income Ratio)', definition: 'Your monthly debt payments divided by your gross monthly income, expressed as a percentage.', explanation: 'Lenders use DTI to assess whether you can afford a mortgage. Lower DTI generally improves eligibility.', example: 'If your income is $6,000 and debt payments are $2,100, your DTI is 35%.', relatedGuides: [{ label: 'How Lenders Calculate DTI', href: '/mortgage/how-dti-calculated' }, { label: 'Debt-to-Income Explained', href: '/mortgage/debt-to-income-explained' }], relatedTerms: ['debt-to-income-ratio', 'qualification', 'front-end-dti'] },
  { slug: 'ltv', term: 'LTV (Loan-to-Value)', definition: 'The loan amount divided by the property value (or purchase price), expressed as a percentage.', explanation: 'LTV measures how much you are borrowing relative to the value of the home. Lower LTV often means better rates and no PMI at 80% or below.', example: 'A $240,000 loan on a $300,000 home is 80% LTV.', relatedGuides: [{ label: 'Loan-to-Value LTV Explained', href: '/mortgage/loan-to-value-ltv' }, { label: 'Private Mortgage Insurance PMI', href: '/mortgage/private-mortgage-insurance-pmi' }], relatedTerms: ['cltv', 'private-mortgage-insurance', 'down-payment'] },
  { slug: 'loan-estimate', term: 'Loan Estimate', definition: 'A standardized form lenders must provide within three business days of receiving a mortgage application, showing estimated terms and costs.', explanation: 'The Loan Estimate lets you compare offers from different lenders. It is not a commitment; actual terms may change.', relatedGuides: [{ label: 'Loan Estimate Explained', href: '/mortgage/loan-estimate-explained' }], relatedTerms: ['closing-disclosure', 'good-faith-estimate', 'apr'] },
  { slug: 'closing-disclosure', term: 'Closing Disclosure', definition: 'A form you receive at least three business days before closing that lists the final loan terms, closing costs, and cash to close.', explanation: 'Compare the Closing Disclosure to your Loan Estimate to catch changes. You have a right to review before closing.', relatedGuides: [{ label: 'Closing Disclosure Explained', href: '/mortgage/closing-disclosure-explained' }], relatedTerms: ['loan-estimate', 'closing-costs', 'cash-to-close'] },
  { slug: 'mortgage-points', term: 'Mortgage Points', definition: 'Fees paid at closing in exchange for a lower interest rate. One point typically equals 1% of the loan amount.', explanation: 'Buying points can reduce your rate and monthly payment. Whether it pays off depends on how long you keep the loan.', relatedGuides: [{ label: 'Mortgage Points Explained', href: '/mortgage/mortgage-points-explained' }, { label: 'Discount vs Origination Points', href: '/mortgage/discount-vs-origination-points' }], relatedTerms: ['discount-points', 'origination-fee', 'rate-lock'] },
  { slug: 'private-mortgage-insurance', term: 'Private Mortgage Insurance (PMI)', definition: 'Insurance that protects the lender when the borrower puts less than 20% down on a conventional loan.', explanation: 'PMI is typically required until you reach about 80% loan-to-value. You may request cancellation or refinance to remove it.', relatedGuides: [{ label: 'Private Mortgage Insurance PMI', href: '/mortgage/private-mortgage-insurance-pmi' }, { label: 'When Can You Remove PMI', href: '/mortgage/when-remove-pmi' }], relatedTerms: ['ltv', 'fha-mip', 'conventional-loan'] },
  { slug: 'escrow-account', term: 'Escrow Account', definition: 'An account held by the lender into which you pay property taxes and insurance; the lender pays these on your behalf.', explanation: 'Escrow spreads tax and insurance costs over 12 months. Lenders may require it when LTV is high or by law in some states.', relatedGuides: [{ label: 'What Is Escrow', href: '/mortgage/escrow-explained' }], relatedTerms: ['impound-account', 'piti', 'closing-costs'] },
  { slug: 'amortization', term: 'Amortization', definition: 'The process of paying off a loan over time through regular payments that cover principal and interest.', explanation: 'Early in the term, most of each payment goes to interest; over time, more goes to principal.', relatedGuides: [{ label: 'What Is Amortization', href: '/mortgage/what-is-amortization' }, { label: 'Principal and Interest Explained', href: '/mortgage/principal-and-interest' }], relatedTerms: ['principal', 'interest', 'amortization-schedule'] },
  { slug: 'rate-lock', term: 'Rate Lock', definition: 'A guarantee that your interest rate (and sometimes points) will not change for a set period, usually until closing.', explanation: 'Locking protects you from rate increases. Lock periods (e.g., 30 or 45 days) may have different rates or fees.', relatedGuides: [{ label: 'What Is a Rate Lock', href: '/mortgage/rate-lock-explained' }], relatedTerms: ['mortgage-points', 'float-down', 'closing'] },
  { slug: 'debt-to-income-ratio', term: 'Debt-to-Income Ratio', definition: 'A ratio of your monthly debt payments to your gross monthly income, used by lenders to qualify you.', relatedGuides: [{ label: 'Debt-to-Income Explained', href: '/mortgage/debt-to-income-explained' }], relatedTerms: ['dti', 'front-end-dti', 'qualification'] },
  { slug: 'conforming-loan', term: 'Conforming Loan', definition: 'A mortgage that meets Fannie Mae and Freddie Mac size and guideline limits, allowing sale on the secondary market.', relatedGuides: [{ label: 'Conventional Loan Guide', href: '/mortgage/conventional-loan' }, { label: 'Conforming Loan Limits', href: '/mortgage/conforming-loan-limits' }], relatedTerms: ['jumbo-loan', 'loan-limits', 'conventional-loan'] },
  { slug: 'jumbo-loan', term: 'Jumbo Loan', definition: 'A mortgage that exceeds the conforming loan limits set by the FHFA. Often has stricter underwriting.', relatedGuides: [{ label: 'Jumbo Loan Explained', href: '/mortgage/jumbo-loan' }], relatedTerms: ['conforming-loan', 'loan-limits'] },
  { slug: 'fha-loan', term: 'FHA Loan', definition: 'A mortgage insured by the Federal Housing Administration (FHA), often allowing lower down payments and more flexible credit.', relatedGuides: [{ label: 'FHA Loan Guide', href: '/mortgage/fha-loan' }], relatedTerms: ['fha-mip', 'usda-loan', 'va-loan'] },
  { slug: 'va-loan', term: 'VA Loan', definition: 'A mortgage guaranteed by the Department of Veterans Affairs for eligible veterans and service members. Often no down payment.', relatedGuides: [{ label: 'VA Loan Guide', href: '/mortgage/va-loan' }], relatedTerms: ['funding-fee', 'fha-loan', 'conventional-loan'] },
  { slug: 'usda-loan', term: 'USDA Loan', definition: 'A mortgage backed by the U.S. Department of Agriculture for eligible rural and suburban properties. No down payment in many cases.', relatedGuides: [{ label: 'USDA Loan Guide', href: '/mortgage/usda-loan' }], relatedTerms: ['fha-loan', 'va-loan'] },
  { slug: 'heloc', term: 'HELOC', definition: 'Home Equity Line of Credit — a revolving line of credit secured by your home equity. You draw and repay over a draw period.', relatedGuides: [{ label: 'HELOC Overview', href: '/mortgage/heloc' }, { label: 'Home Equity Loan vs HELOC', href: '/mortgage/home-equity-loan-vs-heloc' }], relatedTerms: ['home-equity-loan', 'cash-out-refinance', 'ltv'] },
  { slug: 'cash-out-refinance', term: 'Cash-Out Refinance', definition: 'Refinancing for more than you owe and taking the difference in cash. The new loan pays off the old one and gives you funds.', relatedGuides: [{ label: 'Cash-Out Refinance', href: '/mortgage/refinance-cashout' }], relatedTerms: ['heloc', 'home-equity-loan', 'refinance'] },
  { slug: 'piti', term: 'PITI', definition: 'Principal, Interest, Taxes, and Insurance — the four components of a typical monthly mortgage payment.', relatedGuides: [{ label: 'What Is PITI', href: '/mortgage/what-is-piti' }, { label: 'Principal and Interest Explained', href: '/mortgage/principal-and-interest' }], relatedTerms: ['escrow-account', 'amortization'] },
  { slug: 'good-faith-estimate', term: 'Good Faith Estimate (GFE)', definition: 'Pre-2015 form that estimated loan terms and closing costs. Replaced by the Loan Estimate for most applications.', relatedGuides: [{ label: 'What Is a Good Faith Estimate', href: '/mortgage/good-faith-estimate' }], relatedTerms: ['loan-estimate', 'closing-disclosure'] },
  { slug: 'tila', term: 'TILA (Truth in Lending Act)', definition: 'Federal law requiring disclosure of loan terms and costs so borrowers can compare offers. APR and right of rescission come from TILA.', relatedGuides: [{ label: 'Truth in Lending TILA', href: '/mortgage/truth-in-lending-tila' }], relatedTerms: ['apr', 'respa', 'loan-estimate'] },
  { slug: 'respa', term: 'RESPA (Real Estate Settlement Procedures Act)', definition: 'Federal law that governs closing and settlement disclosures and limits kickbacks. Loan Estimate and Closing Disclosure are RESPA-related.', relatedGuides: [{ label: 'Closing Disclosure Explained', href: '/mortgage/closing-disclosure-explained' }], relatedTerms: ['tila', 'loan-estimate', 'closing-disclosure'] },
  { slug: 'qualified-mortgage', term: 'Qualified Mortgage (QM)', definition: 'A category of mortgage that meets federal ability-to-repay rules. Lenders get certain legal protections for QM loans.', relatedGuides: [{ label: 'What Is a Qualified Mortgage', href: '/mortgage/qualified-mortgage-qm' }], relatedTerms: ['atr', 'non-qm', 'dti'] },
  { slug: 'atr', term: 'Ability to Repay (ATR)', definition: 'Federal rule requiring lenders to make a reasonable, good-faith determination that the borrower can repay the loan.', relatedGuides: [{ label: 'What Is a Qualified Mortgage', href: '/mortgage/qualified-mortgage-qm' }], relatedTerms: ['qualified-mortgage', 'dti', 'underwriting'] },
  { slug: 'appraisal', term: 'Appraisal', definition: 'An opinion of a property’s value by a licensed appraiser. Lenders use it to ensure the loan does not exceed the property’s value.', relatedGuides: [{ label: 'What Are Closing Costs', href: '/mortgage/closing-costs-explained' }], relatedTerms: ['ltv', 'closing-costs'] },
  { slug: 'title-insurance', term: 'Title Insurance', definition: 'Insurance that protects the lender (and optionally the owner) against defects in the property’s title.', relatedGuides: [{ label: 'Closing Cost Breakdown', href: '/mortgage/closing-cost-breakdown' }], relatedTerms: ['closing-costs', 'closing'] },
  { slug: 'origination-fee', term: 'Origination Fee', definition: 'A fee charged by the lender for processing and originating the loan. May be a percentage of the loan or a flat fee.', relatedGuides: [{ label: 'Closing Cost Breakdown', href: '/mortgage/closing-cost-breakdown' }], relatedTerms: ['discount-points', 'mortgage-points', 'closing-costs'] },
  { slug: 'discount-points', term: 'Discount Points', definition: 'Points you pay to lower the interest rate. One point usually equals 1% of the loan amount and may reduce the rate by about 0.25%.', relatedGuides: [{ label: 'Mortgage Points Explained', href: '/mortgage/mortgage-points-explained' }], relatedTerms: ['mortgage-points', 'origination-fee', 'rate-lock'] },
  { slug: 'origination-points', term: 'Origination Points', definition: 'Fees charged for creating the loan, often expressed as a percentage of the loan amount. Not the same as discount points.', relatedGuides: [{ label: 'Discount vs Origination Points', href: '/mortgage/discount-vs-origination-points' }], relatedTerms: ['discount-points', 'origination-fee'] },
  { slug: 'prepaid-interest', term: 'Prepaid Interest', definition: 'Interest charged from the closing date until the first regular payment date. Often listed as “per diem” interest at closing.', relatedGuides: [{ label: 'Closing Cost Breakdown', href: '/mortgage/closing-cost-breakdown' }], relatedTerms: ['closing-costs', 'amortization'] },
  { slug: 'impound-account', term: 'Impound Account', definition: 'Another name for an escrow account — holds funds for property taxes and insurance.', relatedTerms: ['escrow-account', 'piti'] },
  { slug: 'fha-mip', term: 'FHA MIP (Mortgage Insurance Premium)', definition: 'Insurance required on FHA loans. Includes an upfront premium (UFMIP) and an annual premium paid in monthly installments.', relatedGuides: [{ label: 'FHA MIP Explained', href: '/mortgage/fha-mip-explained' }, { label: 'FHA Loan Guide', href: '/mortgage/fha-loan' }], relatedTerms: ['private-mortgage-insurance', 'ufmip', 'fha-loan'] },
  { slug: 'ufmip', term: 'UFMIP (Upfront Mortgage Insurance Premium)', definition: 'One-time FHA mortgage insurance premium paid at closing or financed into the loan.', relatedGuides: [{ label: 'FHA MIP Explained', href: '/mortgage/fha-mip-explained' }], relatedTerms: ['fha-mip', 'fha-loan'] },
  { slug: 'funding-fee', term: 'VA Funding Fee', definition: 'A one-time fee on VA loans that helps fund the program. Amount depends on down payment and whether you’ve used VA benefits before.', relatedGuides: [{ label: 'VA Loan Guide', href: '/mortgage/va-loan' }], relatedTerms: ['va-loan'] },
  { slug: 'servicing', term: 'Mortgage Servicing', definition: 'The administration of a mortgage after origination: collecting payments, managing escrow, sending statements, handling payoffs.', relatedGuides: [{ label: 'What Is a Mortgage Servicer', href: '/mortgage/what-is-a-mortgage-servicer' }], relatedTerms: ['escrow-account', 'transfer-of-servicing'] },
  { slug: 'transfer-of-servicing', term: 'Transfer of Servicing', definition: 'When the right to collect your payments and manage your loan is sold or transferred to another company.', relatedTerms: ['servicing'] },
  { slug: 'assumable-mortgage', term: 'Assumable Mortgage', definition: 'A mortgage that allows a new buyer to take over the existing loan and its terms. Common with some FHA and VA loans.', relatedGuides: [{ label: 'FHA Loan Guide', href: '/mortgage/fha-loan' }, { label: 'VA Loan Guide', href: '/mortgage/va-loan' }], relatedTerms: ['fha-loan', 'va-loan'] },
  { slug: 'bridge-loan', term: 'Bridge Loan', definition: 'Short-term financing used to “bridge” the gap between buying a new home and selling the current one.', relatedTerms: ['heloc', 'conventional-loan'] },
  { slug: 'construction-loan', term: 'Construction Loan', definition: 'Short-term financing for building a home. Often converts to a permanent mortgage or is paid off when construction is complete.', relatedTerms: ['conventional-loan', 'fha-203k'] },
  { slug: 'principal', term: 'Principal', definition: 'The amount borrowed (loan balance). Each payment reduces principal until the loan is paid off.', relatedGuides: [{ label: 'Principal and Interest Explained', href: '/mortgage/principal-and-interest' }], relatedTerms: ['interest', 'amortization', 'piti'] },
  { slug: 'interest', term: 'Interest', definition: 'The cost of borrowing money, usually expressed as an annual percentage of the principal.', relatedGuides: [{ label: 'How Mortgage Interest Works', href: '/mortgage/how-mortgage-interest-works' }], relatedTerms: ['principal', 'apr', 'amortization'] },
  { slug: 'interest-rate', term: 'Interest Rate', definition: 'The percentage of the loan amount charged as interest each year. Does not include fees (see APR).', relatedGuides: [{ label: 'Mortgage Rate vs APR', href: '/mortgage/mortgage-rate-vs-apr' }], relatedTerms: ['apr', 'rate-lock', 'mortgage-points'] },
  { slug: 'fixed-rate-mortgage', term: 'Fixed-Rate Mortgage', definition: 'A mortgage whose interest rate stays the same for the entire term (e.g., 30 years).', relatedGuides: [{ label: 'Fixed-Rate vs ARM', href: '/mortgage/fixed-vs-arm' }], relatedTerms: ['arm', 'interest-rate'] },
  { slug: 'arm', term: 'ARM (Adjustable-Rate Mortgage)', definition: 'A mortgage whose interest rate can change after an initial fixed period (e.g., 5/1 ARM: fixed 5 years, then adjusts annually).', relatedGuides: [{ label: 'Fixed-Rate vs ARM', href: '/mortgage/fixed-vs-arm' }, { label: '5/1 ARM Explained', href: '/mortgage/5-1-arm-explained' }], relatedTerms: ['fixed-rate-mortgage', 'rate-caps', 'teaser-rate'] },
  { slug: 'rate-caps', term: 'ARM Rate Caps', definition: 'Limits on how much an adjustable-rate mortgage’s rate can change at each adjustment and over the life of the loan.', relatedGuides: [{ label: 'ARM Caps and Floors', href: '/mortgage/arm-caps-floors' }], relatedTerms: ['arm', 'lifetime-cap'] },
  { slug: 'teaser-rate', term: 'Teaser Rate', definition: 'An initial lower rate on an ARM that later adjusts to a higher rate. The “teaser” is the initial discount.', relatedTerms: ['arm', 'rate-caps'] },
  { slug: 'closing-costs', term: 'Closing Costs', definition: 'Fees and charges paid at closing, including origination, appraisal, title insurance, and prepaid items.', relatedGuides: [{ label: 'What Are Closing Costs', href: '/mortgage/closing-costs-explained' }, { label: 'How Much Are Closing Costs', href: '/mortgage/how-much-closing-costs' }], relatedTerms: ['loan-estimate', 'closing-disclosure', 'cash-to-close'] },
  { slug: 'cash-to-close', term: 'Cash to Close', definition: 'The total amount the borrower must bring to closing: down payment plus closing costs minus credits.', relatedGuides: [{ label: 'Closing Disclosure Explained', href: '/mortgage/closing-disclosure-explained' }], relatedTerms: ['closing-costs', 'down-payment', 'closing-disclosure'] },
  { slug: 'down-payment', term: 'Down Payment', definition: 'The portion of the purchase price you pay upfront. The rest is financed. Larger down payments can mean better rates and no PMI.', relatedGuides: [{ label: 'How Much Down Payment for a House', href: '/mortgage/down-payment-requirements' }], relatedTerms: ['ltv', 'private-mortgage-insurance', 'closing-costs'] },
  { slug: 'conventional-loan', term: 'Conventional Loan', definition: 'A mortgage not backed by the federal government (not FHA, VA, or USDA). Often conforms to Fannie/Freddie guidelines.', relatedGuides: [{ label: 'Conventional Loan Guide', href: '/mortgage/conventional-loan' }], relatedTerms: ['conforming-loan', 'jumbo-loan', 'private-mortgage-insurance'] },
  { slug: 'non-qm', term: 'Non-QM Loan', definition: 'A mortgage that does not meet Qualified Mortgage criteria. May use alternative documentation (e.g., bank statements) or different underwriting.', relatedGuides: [{ label: 'Non-QM Loan Guide', href: '/mortgage/non-qm-loan' }], relatedTerms: ['qualified-mortgage', 'bank-statement-loan', 'dscr'] },
  { slug: 'refinance', term: 'Refinance', definition: 'Replacing an existing mortgage with a new one, often to get a lower rate, change the term, or access equity.', relatedGuides: [{ label: 'Refinance Overview', href: '/mortgage/refinance' }, { label: 'Should I Refinance', href: '/mortgage/should-i-refinance' }], relatedTerms: ['cash-out-refinance', 'rate-and-term-refinance', 'break-even'] },
  { slug: 'rate-and-term-refinance', term: 'Rate and Term Refinance', definition: 'Refinancing to change the interest rate and/or loan term without taking cash out. No increase in principal.', relatedGuides: [{ label: 'Rate and Term Refinance', href: '/mortgage/rate-and-term-refinance' }], relatedTerms: ['refinance', 'cash-out-refinance'] },
  { slug: 'break-even', term: 'Refinance Break-Even', definition: 'The point at which savings from a refinance equal the closing costs. After break-even, you save money.', relatedGuides: [{ label: 'Refinance Break-Even', href: '/mortgage/refinance-break-even' }], relatedTerms: ['refinance', 'closing-costs'] },
  { slug: 'home-equity-loan', term: 'Home Equity Loan', definition: 'A lump-sum loan secured by home equity. Fixed rate and payment, unlike a HELOC.', relatedGuides: [{ label: 'Home Equity Loan vs HELOC', href: '/mortgage/home-equity-loan-vs-heloc' }], relatedTerms: ['heloc', 'cash-out-refinance', 'ltv'] },
  { slug: 'cltv', term: 'CLTV (Combined Loan-to-Value)', definition: 'The sum of all liens on the property divided by the property value. Used when you have a first mortgage plus HELOC or second.', relatedTerms: ['ltv', 'heloc', 'home-equity-loan'] },
  { slug: 'reverse-mortgage', term: 'Reverse Mortgage', definition: 'A loan that lets homeowners 62+ convert home equity into cash. No monthly principal/interest payments; loan is repaid when the home is sold or the borrower leaves.', relatedGuides: [{ label: 'Reverse Mortgage Guide', href: '/mortgage/reverse' }], relatedTerms: ['heloc', 'home-equity', 'hecm'] },
  { slug: 'hecm', term: 'HECM (Home Equity Conversion Mortgage)', definition: 'The most common type of reverse mortgage, insured by the FHA.', relatedGuides: [{ label: 'Reverse Mortgage Guide', href: '/mortgage/reverse' }], relatedTerms: ['reverse-mortgage', 'fha-loan'] },
  { slug: 'promissory-note', term: 'Promissory Note', definition: 'A legal document in which the borrower promises to repay the loan under specified terms.', relatedGuides: [{ label: 'What Is a Promissory Note', href: '/mortgage/promissory-note' }], relatedTerms: ['deed-of-trust', 'mortgage'] },
  { slug: 'deed-of-trust', term: 'Deed of Trust', definition: 'A document that gives a third party (trustee) a security interest in the property until the loan is paid. Used in many states instead of a mortgage.', relatedGuides: [{ label: 'Deed of Trust vs Mortgage', href: '/mortgage/deed-of-trust-vs-mortgage' }], relatedTerms: ['promissory-note', 'mortgage', 'foreclosure'] },
  { slug: 'foreclosure', term: 'Foreclosure', definition: 'The legal process by which a lender takes possession of the property when the borrower defaults on the loan.', relatedTerms: ['deed-of-trust', 'default'] },
  { slug: 'prequalification', term: 'Prequalification', definition: 'A preliminary estimate of how much you might borrow based on self-reported information. Not a commitment.', relatedGuides: [{ label: 'Prequalification vs Pre-approval', href: '/mortgage/prequalify' }], relatedTerms: ['pre-approval', 'underwriting'] },
  { slug: 'pre-approval', term: 'Pre-approval', definition: 'A lender’s conditional commitment to lend after reviewing your finances. Stronger than prequalification; often involves a credit check.', relatedGuides: [{ label: 'Mortgage Pre-approval Process', href: '/mortgage/pre-approval-process' }], relatedTerms: ['prequalification', 'underwriting'] },
  { slug: 'underwriting', term: 'Underwriting', definition: 'The process of evaluating a borrower’s credit, income, and the property to decide whether to approve the loan and on what terms.', relatedGuides: [{ label: 'What Lenders Look For', href: '/mortgage/what-lenders-look-for' }], relatedTerms: ['pre-approval', 'atr', 'approval'] },
  { slug: 'loan-limits', term: 'Loan Limits', definition: 'Maximum loan amounts for conforming, FHA, VA, and other programs. Vary by area and are updated annually.', relatedGuides: [{ label: 'Conforming Loan Limits', href: '/mortgage/conforming-loan-limits' }, { label: 'FHA Loan Limits', href: '/mortgage/fha-loan-limits' }], relatedTerms: ['conforming-loan', 'jumbo-loan', 'fha-loan'] },
  { slug: 'front-end-dti', term: 'Front-End DTI', definition: 'Housing costs (PITI) divided by gross monthly income. A subset of total DTI that focuses on the mortgage.', relatedTerms: ['dti', 'debt-to-income-ratio', 'qualification'] },
  { slug: 'back-end-dti', term: 'Back-End DTI', definition: 'All monthly debt payments (including housing) divided by gross monthly income. The DTI most commonly used by lenders.', relatedTerms: ['dti', 'front-end-dti'] },
  { slug: 'amortization-schedule', term: 'Amortization Schedule', definition: 'A table showing each payment’s split between principal and interest and the remaining balance over the life of the loan.', relatedGuides: [{ label: 'What Is Amortization', href: '/mortgage/what-is-amortization' }], relatedTerms: ['amortization', 'principal', 'interest'] },
  { slug: 'float-down', term: 'Float Down', definition: 'An option to lower your locked rate if market rates drop before closing. May have a fee or specific rules.', relatedGuides: [{ label: 'Lock Float Down', href: '/mortgage/lock-float-down' }], relatedTerms: ['rate-lock'] },
  { slug: 'lender-paid-mi', term: 'Lender-Paid MI', definition: 'Mortgage insurance where the lender pays the premium in exchange for a higher interest rate.', relatedGuides: [{ label: 'Lender-Paid MI', href: '/mortgage/lender-paid-mi' }], relatedTerms: ['private-mortgage-insurance', 'pmi'] },
  { slug: 'streamline-refinance', term: 'Streamline Refinance', definition: 'A simplified refinance (FHA or VA) with reduced documentation and sometimes no appraisal. Focus is on rate/term improvement.', relatedGuides: [{ label: 'Streamline Refinance FHA VA', href: '/mortgage/streamline-refinance' }], relatedTerms: ['fha-loan', 'va-loan', 'refinance'] },
  { slug: 'fha-203k', term: 'FHA 203(k)', definition: 'An FHA program that finances the purchase (or refinance) of a home plus repairs or improvements in one loan.', relatedGuides: [{ label: 'FHA 203k Rehabilitation Loan', href: '/mortgage/fha-203k' }], relatedTerms: ['fha-loan', 'construction-loan'] },
  { slug: 'bank-statement-loan', term: 'Bank Statement Loan', definition: 'A non-QM loan that uses bank statements instead of tax returns to verify income. Often used by self-employed borrowers.', relatedGuides: [{ label: 'Self-Employed Borrower', href: '/mortgage/self-employed-borrower' }, { label: 'Non-QM Loan Guide', href: '/mortgage/non-qm-loan' }], relatedTerms: ['non-qm', 'dscr', 'self-employed'] },
  { slug: 'dscr', term: 'DSCR (Debt Service Coverage Ratio)', definition: 'For investment properties: net rental income divided by the mortgage payment. Lenders use it to assess if the property can support the loan.', relatedGuides: [{ label: 'DSCR Loans', href: '/mortgage/dscr-loans' }, { label: 'Investment Property Mortgage', href: '/mortgage/investment-property-mortgage' }], relatedTerms: ['non-qm', 'investment-property'] },
  { slug: 'qualification', term: 'Qualification', definition: 'Meeting a lender’s criteria for credit, income, assets, and property to be approved for a mortgage.', relatedGuides: [{ label: 'What Lenders Look For', href: '/mortgage/what-lenders-look-for' }], relatedTerms: ['dti', 'ltv', 'credit-score', 'underwriting'] },
  { slug: 'credit-score', term: 'Credit Score', definition: 'A number that summarizes your creditworthiness based on credit report data. Lenders use it to set rates and approve loans.', relatedGuides: [{ label: 'What Credit Score for Mortgage', href: '/mortgage/credit-score-for-mortgage' }], relatedTerms: ['dti', 'qualification', 'fha-loan'] },
  { slug: 'gift-funds', term: 'Gift Funds', definition: 'Money given to the borrower for the down payment or closing costs. Lenders often allow gifts from family with a gift letter.', relatedGuides: [{ label: 'Gift Funds for Down Payment', href: '/mortgage/gift-funds-down-payment' }], relatedTerms: ['down-payment', 'closing-costs'] },
  { slug: 'down-payment-assistance', term: 'Down Payment Assistance', definition: 'Programs (grants, loans, or forgivable loans) that help eligible buyers with the down payment or closing costs.', relatedGuides: [{ label: 'Down Payment Assistance Programs', href: '/mortgage/down-payment-assistance' }], relatedTerms: ['down-payment', 'first-time-buyer'] },
  { slug: 'first-time-buyer', term: 'First-Time Home Buyer', definition: 'A buyer who has not owned a home in the past three years (for many programs) or meets other program definitions.', relatedGuides: [{ label: 'First-Time Home Buyer Guide', href: '/mortgage/first-time-home-buyer' }], relatedTerms: ['down-payment-assistance', 'fha-loan'] },
  { slug: 'investment-property', term: 'Investment Property', definition: 'A property purchased for rental income or resale, not as a primary or second home. Often has stricter loan terms.', relatedGuides: [{ label: 'Investment Property Mortgage', href: '/mortgage/investment-property-mortgage' }], relatedTerms: ['dscr', 'conventional-loan'] },
  { slug: 'primary-residence', term: 'Primary Residence', definition: 'The home where you live most of the time. Many programs (FHA, VA, some conventional) require the property to be your primary residence.', relatedTerms: ['fha-loan', 'second-home', 'investment-property'] },
  { slug: 'second-home', term: 'Second Home', definition: 'A property you occupy part of the year but is not your primary residence. Lenders have specific rules for second-home financing.', relatedGuides: [{ label: 'Second Home Mortgage', href: '/mortgage/second-home-mortgage' }], relatedTerms: ['primary-residence', 'investment-property'] },
  { slug: 'condo', term: 'Condo (Condominium)', definition: 'A unit in a building or complex with shared common areas. Condo loans may have project approval requirements.', relatedGuides: [{ label: 'Condo Mortgage', href: '/mortgage/condo-mortgage' }], relatedTerms: ['fha-loan', 'conventional-loan'] },
  { slug: 'manufactured-home', term: 'Manufactured Home', definition: 'A factory-built home that meets HUD code. Financing may differ from site-built homes.', relatedGuides: [{ label: 'Manufactured Home Mortgage', href: '/mortgage/manufactured-home-mortgage' }], relatedTerms: ['fha-loan', 'usda-loan'] },
  { slug: 'portfolio-loan', term: 'Portfolio Loan', definition: 'A loan the lender keeps in its own portfolio instead of selling to Fannie Mae, Freddie Mac, or others. May have more flexible criteria.', relatedGuides: [{ label: 'Portfolio Loans', href: '/mortgage/portfolio-loan' }], relatedTerms: ['non-qm', 'conforming-loan'] },
  { slug: 'balloon-mortgage', term: 'Balloon Mortgage', definition: 'A loan with small payments for a period, then a large “balloon” payment of the remaining balance at the end.', relatedGuides: [{ label: 'What Is a Balloon Mortgage', href: '/mortgage/balloon-mortgage' }], relatedTerms: ['interest-only-mortgage'] },
  { slug: 'interest-only-mortgage', term: 'Interest-Only Mortgage', definition: 'A loan where you pay only interest for a set period; after that, principal (and sometimes higher payments) is required.', relatedGuides: [{ label: 'Interest-Only Mortgage', href: '/mortgage/interest-only-mortgage' }], relatedTerms: ['arm', 'balloon-mortgage'] },
  { slug: 'biweekly-payment', term: 'Biweekly Payment', definition: 'Making half the monthly payment every two weeks. Results in one extra full payment per year and faster payoff.', relatedGuides: [{ label: 'Biweekly Mortgage Payments', href: '/mortgage/biweekly-payments' }], relatedTerms: ['amortization', 'paying-off-early'] },
  { slug: 'paying-off-early', term: 'Paying Off Mortgage Early', definition: 'Making extra principal payments or paying off the loan before the end of the term. May reduce total interest; check for prepayment penalties.', relatedGuides: [{ label: 'Paying Off Mortgage Early', href: '/mortgage/paying-off-mortgage-early' }], relatedTerms: ['amortization', 'principal', 'prepayment-penalty'] },
  { slug: 'prepayment-penalty', term: 'Prepayment Penalty', definition: 'A fee charged if you pay off or significantly pay down the loan within a specified period.', relatedTerms: ['paying-off-early', 'refinance'] },
  { slug: 'loan-modification', term: 'Loan Modification', definition: 'A change to the original loan terms (e.g., rate, term) to make payments affordable. Often used to avoid foreclosure.', relatedTerms: ['foreclosure', 'hardship'] },
  { slug: 'forbearance', term: 'Forbearance', definition: 'An agreement to temporarily pause or reduce payments. Common during hardship; terms vary by lender and program.', relatedTerms: ['loan-modification', 'foreclosure'] },
  { slug: 'short-sale', term: 'Short Sale', definition: 'Selling the home for less than the mortgage balance with the lender’s approval. The lender may forgive the shortfall.', relatedTerms: ['foreclosure', 'underwater'] },
  { slug: 'underwater', term: 'Underwater (Upside Down)', definition: 'Owing more on the mortgage than the property is worth. Limits refinance and sale options.', relatedTerms: ['short-sale', 'refinance'] },
  { slug: 'loan-to-value-ltv', term: 'Loan-to-Value (LTV) Ratio', definition: 'Loan amount divided by property value or purchase price, as a percentage. Key for PMI, pricing, and eligibility.', relatedGuides: [{ label: 'Loan-to-Value LTV Explained', href: '/mortgage/loan-to-value-ltv' }], relatedTerms: ['ltv', 'cltv', 'down-payment'] },
  { slug: 'high-cost-area', term: 'High-Cost Area', definition: 'A region where conforming and FHA loan limits are higher due to elevated home prices.', relatedGuides: [{ label: 'High-Cost Area Loan Limits', href: '/mortgage/high-cost-loan-limits' }], relatedTerms: ['loan-limits', 'conforming-loan'] },
  { slug: 'mortgage-broker', term: 'Mortgage Broker', definition: 'An intermediary who connects borrowers with lenders and may process the loan. Does not fund the loan.', relatedGuides: [{ label: 'Mortgage Broker vs Lender', href: '/mortgage/broker-vs-lender' }], relatedTerms: ['lender', 'originator'] },
  { slug: 'lender', term: 'Lender', definition: 'The entity that provides the funds for the mortgage. Can be a bank, credit union, or nonbank lender.', relatedGuides: [{ label: 'Choosing a Mortgage Lender', href: '/mortgage/choosing-a-lender' }], relatedTerms: ['mortgage-broker', 'servicing'] },
  { slug: 'originator', term: 'Loan Originator', definition: 'The person or entity that takes the application and works with the borrower. May work for a lender or broker.', relatedTerms: ['mortgage-broker', 'lender'] },
  { slug: 'loan-officer', term: 'Loan Officer', definition: 'A representative of a lender or broker who assists borrowers with the application and loan selection.', relatedTerms: ['originator', 'lender'] },
  { slug: 'contingency', term: 'Mortgage Contingency', definition: 'A contract clause that makes the sale contingent on the buyer obtaining financing. Protects the buyer if the loan is denied.', relatedGuides: [{ label: 'Mortgage Contingency in Contract', href: '/mortgage/mortgage-contingency' }], relatedTerms: ['pre-approval', 'closing'] },
  { slug: 'final-walk-through', term: 'Final Walk-Through', definition: 'A last visit to the property before closing to confirm condition and that agreed repairs were made.', relatedGuides: [{ label: 'Final Walk-Through', href: '/mortgage/final-walk-through' }], relatedTerms: ['closing'] },
  { slug: 'closing', term: 'Closing', definition: 'The meeting where the loan is finalized, documents are signed, and ownership and funds are transferred.', relatedGuides: [{ label: 'What Happens at Closing', href: '/mortgage/what-happens-at-closing' }], relatedTerms: ['closing-disclosure', 'closing-costs', 'cash-to-close'] },
  { slug: 'clear-to-close', term: 'Clear to Close', definition: 'Lender approval indicating that conditions are satisfied and the loan can close.', relatedTerms: ['underwriting', 'closing'] },
  { slug: 'lifetime-cap', term: 'Lifetime Cap', definition: 'The maximum rate increase allowed over the life of an ARM.', relatedGuides: [{ label: 'ARM Caps and Floors', href: '/mortgage/arm-caps-floors' }], relatedTerms: ['arm', 'rate-caps'] },
  { slug: 'payment-cap', term: 'Payment Cap', definition: 'A limit on how much the monthly payment can increase at each adjustment on some ARMs.', relatedTerms: ['arm', 'rate-caps'] },
  { slug: 'negative-amortization', term: 'Negative Amortization', definition: 'When the payment is too small to cover interest, so the loan balance increases. Rare in standard mortgages today.', relatedTerms: ['arm', 'amortization'] },
  { slug: 'index', term: 'Rate Index', definition: 'A benchmark rate (e.g., SOFR, Treasury) to which an ARM’s rate is tied after the initial fixed period.', relatedTerms: ['arm', 'margin'] },
  { slug: 'margin', term: 'ARM Margin', definition: 'A percentage added to the index to determine the ARM’s rate at each adjustment.', relatedTerms: ['arm', 'index'] },
  { slug: 'sofr', term: 'SOFR (Secured Overnight Financing Rate)', definition: 'A benchmark rate that has replaced LIBOR for many ARMs and other loans.', relatedTerms: ['arm', 'index'] },
  { slug: 'libor', term: 'LIBOR', definition: 'London Interbank Offered Rate — a former benchmark being phased out and replaced by SOFR.', relatedTerms: ['sofr', 'arm'] },
  { slug: 'usda-guarantee-fee', term: 'USDA Guarantee Fee', definition: 'An upfront and annual fee on USDA loans that helps fund the program.', relatedGuides: [{ label: 'USDA Loan Guide', href: '/mortgage/usda-loan' }], relatedTerms: ['usda-loan'] },
  { slug: 'non-warrantable-condo', term: 'Non-Warrantable Condo', definition: 'A condo that does not meet Fannie/Freddie project requirements. May require a non-QM or portfolio loan.', relatedTerms: ['condo', 'portfolio-loan'] },
  { slug: 'recording-fee', term: 'Recording Fee', definition: 'A fee paid to the county or other office to record the deed and mortgage in public records.', relatedTerms: ['closing-costs', 'deed-of-trust'] },
  { slug: 'title-search', term: 'Title Search', definition: 'A review of public records to confirm ownership and uncover liens or other claims on the property.', relatedTerms: ['title-insurance', 'closing-costs'] },
  { slug: 'lien', term: 'Lien', definition: 'A legal claim on property securing a debt. A mortgage is a lien; unpaid taxes or HOA fees can also create liens.', relatedTerms: ['deed-of-trust', 'title-search'] },
  { slug: 'payoff-statement', term: 'Payoff Statement', definition: 'A document from the current lender showing the amount required to pay off the loan, often including per diem interest.', relatedTerms: ['refinance', 'closing'] },
  { slug: 'subordinate', term: 'Subordination', definition: 'When a lien (e.g., HELOC) agrees to remain in second position behind a new first mortgage, such as after a refinance.', relatedTerms: ['heloc', 'refinance'] },
  { slug: 'rate-sheet', term: 'Rate Sheet', definition: 'A lender’s internal list of rates and fees for different loan products and scenarios.', relatedTerms: ['loan-pricing', 'rate-lock'] },
  { slug: 'loan-pricing-adjustments', term: 'Loan-Level Price Adjustments (LLPAs)', definition: 'Fees or credits applied by Fannie/Freddie based on loan and borrower characteristics (e.g., LTV, credit score).', relatedGuides: [{ label: 'How Lenders Price Loans', href: '/mortgage/loan-pricing-adjustments' }], relatedTerms: ['conforming-loan', 'rate-sheet'] },
  { slug: 'yield-spread-premium', term: 'Yield Spread Premium (YSP)', definition: 'Compensation to a broker when the borrower takes a higher rate. Disclosed on the Loan Estimate.', relatedTerms: ['mortgage-broker', 'apr'] },
  { slug: 'affordability', term: 'Affordability', definition: 'How much home or monthly payment you can afford based on income, debts, and lender criteria.', relatedGuides: [{ label: 'How Much House Can I Afford', href: '/mortgage/down-payment-requirements' }], relatedTerms: ['dti', 'down-payment'] },
  { slug: 'rent-vs-buy', term: 'Rent vs Buy', definition: 'Comparing the costs and benefits of renting versus buying a home. Calculators can illustrate break-even.', relatedTerms: ['affordability', 'down-payment'] },
  { slug: 'seller-concessions', term: 'Seller Concessions', definition: 'Closing costs or other expenses the seller agrees to pay. Limits may apply based on loan type and LTV.', relatedTerms: ['closing-costs', 'cash-to-close'] },
  { slug: 'earnest-money', term: 'Earnest Money', definition: 'A deposit made with an offer to show good faith. Typically held in escrow and applied to down payment or closing.', relatedTerms: ['closing', 'escrow-account'] },
  { slug: 'comparative-market-analysis', term: 'Comparative Market Analysis (CMA)', definition: 'A report comparing similar sold and listed properties to estimate value. Not an appraisal.', relatedTerms: ['appraisal', 'listing-price'] },
  { slug: 'flood-certificate', term: 'Flood Certificate', definition: 'A determination of whether the property is in a FEMA-designated flood zone. Lenders may require flood insurance.', relatedTerms: ['closing-costs', 'homeowners-insurance'] },
  { slug: 'homeowners-insurance', term: "Homeowner's Insurance", definition: 'Insurance that covers damage to the property and liability. Lenders require it and it may be included in PITI via escrow.', relatedTerms: ['piti', 'escrow-account'] },
  { slug: 'pmi-cancellation', term: 'PMI Cancellation', definition: 'Requesting removal of PMI once LTV reaches about 80% (by payment or value increase) or at the loan’s midpoint under some rules.', relatedGuides: [{ label: 'When Can You Remove PMI', href: '/mortgage/when-remove-pmi' }], relatedTerms: ['private-mortgage-insurance', 'ltv'] },
  { slug: 'automatic-termination-pmi', term: 'Automatic PMI Termination', definition: 'PMI must automatically end when the loan reaches 78% LTV (by schedule) or at the midpoint of an amortization schedule under federal rules.', relatedTerms: ['pmi-cancellation', 'private-mortgage-insurance'] },
  { slug: 'second-lien', term: 'Second Lien', definition: 'A loan or lien that is subordinate to the first mortgage (e.g., HELOC, home equity loan, second mortgage).', relatedTerms: ['heloc', 'cltv', 'first-mortgage'] },
  { slug: 'first-mortgage', term: 'First Mortgage', definition: 'The primary loan on the property with first claim in case of foreclosure.', relatedTerms: ['second-lien', 'heloc'] },
  { slug: 'piggyback-loan', term: 'Piggyback Loan', definition: 'A second loan used with a first mortgage to avoid PMI (e.g., 80-10-10: 80% first, 10% second, 10% down).', relatedTerms: ['second-lien', 'private-mortgage-insurance'] },
  { slug: 'construction-permanent-loan', term: 'Construction-to-Permanent Loan', definition: 'A single loan that finances construction and then converts to a permanent mortgage.', relatedTerms: ['construction-loan', 'conventional-loan'] },
  { slug: 'rate-and-term', term: 'Rate and Term Refinance (summary)', definition: 'Refinancing to change rate or term without taking cash out.', relatedTerms: ['refinance', 'cash-out-refinance'] },
  { slug: 'no-closing-cost-refinance', term: 'No-Closing-Cost Refinance', definition: 'A refinance where the lender covers closing costs, often in exchange for a higher rate or rolling costs into the loan.', relatedGuides: [{ label: 'No-Closing-Cost Refinance', href: '/mortgage/no-closing-cost-refinance' }], relatedTerms: ['refinance', 'closing-costs'] },
  { slug: 'credit-report', term: 'Credit Report', definition: 'A record of your credit history used by lenders to evaluate risk. Errors can be disputed.', relatedGuides: [{ label: 'Credit Report and Mortgage', href: '/mortgage/credit-report-mortgage' }], relatedTerms: ['credit-score', 'qualification'] },
  { slug: 'deed', term: 'Deed', definition: 'The document that transfers ownership of the property. At closing, the seller delivers the deed to the buyer.', relatedTerms: ['closing', 'title-insurance'] },
  { slug: 'warranty-deed', term: 'Warranty Deed', definition: 'A deed in which the seller guarantees clear title. Common in many sales.', relatedTerms: ['deed', 'title-search'] },
  { slug: 'quit-claim-deed', term: 'Quitclaim Deed', definition: 'A deed that transfers whatever interest the grantor has, with no warranty of title. Often used between family or to clear title.', relatedTerms: ['deed'] },
  { slug: 'escrow-disbursement', term: 'Escrow Disbursement', definition: 'Payment of property taxes or insurance from the escrow account by the servicer.', relatedTerms: ['escrow-account', 'servicing'] },
  { slug: 'escrow-shortage', term: 'Escrow Shortage', definition: 'When the escrow account has insufficient funds to pay taxes or insurance. May result in higher monthly payments or a shortage payment.', relatedTerms: ['escrow-account'] },
  { slug: 'escrow-analysis', term: 'Escrow Analysis', definition: 'An annual review of the escrow account to adjust the monthly escrow payment for the next year.', relatedTerms: ['escrow-account', 'servicing'] },
  { slug: 'impound', term: 'Impound', definition: 'Same as escrow — holding funds for taxes and insurance.', relatedTerms: ['escrow-account'] },
  { slug: 'annual-cap', term: 'Annual Cap (ARM)', definition: 'The maximum the rate can increase in one year on an ARM.', relatedTerms: ['arm', 'rate-caps'] },
  { slug: 'initial-cap', term: 'Initial Cap (ARM)', definition: 'The maximum the rate can increase at the first adjustment of an ARM.', relatedTerms: ['arm', 'rate-caps'] },
  { slug: 'conversion-option', term: 'ARM Conversion Option', definition: 'A feature on some ARMs that allows converting to a fixed rate during a specified period.', relatedTerms: ['arm', 'fixed-rate-mortgage'] },
  { slug: 'buydown', term: 'Buydown', definition: 'Paying extra upfront (or having the seller pay) to reduce the interest rate for an initial period or the life of the loan.', relatedTerms: ['mortgage-points', 'seller-concessions'] },
  { slug: 'temporary-buydown', term: 'Temporary Buydown', definition: 'A buydown that lowers the rate for the first one to three years, then the rate steps up.', relatedTerms: ['buydown', 'interest-rate'] },
  { slug: 'permanent-buydown', term: 'Permanent Buydown', definition: 'Using discount points to lower the rate for the full term of the loan.', relatedTerms: ['buydown', 'discount-points'] },
  { slug: 'loan-origination', term: 'Loan Origination', definition: 'The process of taking the application, underwriting, and closing the loan.', relatedTerms: ['originator', 'underwriting'] },
  { slug: 'lock-period', term: 'Lock Period', definition: 'The time during which your rate lock is in effect. Longer locks may have higher rates or fees.', relatedTerms: ['rate-lock'] },
  { slug: 'lock-in-fee', term: 'Lock-In Fee', definition: 'A fee sometimes charged to lock the rate. May be refunded at closing or applied to costs.', relatedTerms: ['rate-lock'] },
  { slug: 'recast', term: 'Recast', definition: 'Recalculating the payment after a large principal payment while keeping the same rate and term. Lowers future payments.', relatedTerms: ['paying-off-early', 'amortization'] },
  { slug: 'assumption-fee', term: 'Assumption Fee', definition: 'A fee charged when a new borrower assumes an existing mortgage.', relatedTerms: ['assumable-mortgage'] },
  { slug: 'release-of-liability', term: 'Release of Liability', definition: 'When the VA releases a veteran from obligation on a VA loan after the buyer assumes it (in a VA assumption).', relatedTerms: ['assumable-mortgage', 'va-loan'] },
  { slug: 'due-on-sale', term: 'Due-on-Sale Clause', definition: 'A provision that the full loan balance is due when the property is sold. Limits assumability of most conventional loans.', relatedTerms: ['assumable-mortgage'] },
  { slug: 'mortgage-insurance-premium', term: 'Mortgage Insurance Premium (MIP)', definition: 'FHA’s form of mortgage insurance: upfront and annual premiums.', relatedTerms: ['fha-mip', 'ufmip'] },
  { slug: 'single-payment-mip', term: 'Single-Payment MIP', definition: 'Option to pay FHA upfront MIP in one sum at closing instead of financing it.', relatedTerms: ['fha-mip', 'ufmip'] },
  { slug: 'annual-mip', term: 'Annual MIP', definition: 'The ongoing FHA mortgage insurance premium paid monthly with the mortgage payment.', relatedTerms: ['fha-mip'] },
  { slug: 'mip-duration', term: 'MIP Duration', definition: 'How long FHA MIP must be paid. For many FHA loans it is for the life of the loan unless LTV and other conditions are met.', relatedTerms: ['fha-mip', 'fha-loan'] },
  { slug: 'non-borrowing-spouse', term: 'Non-Borrowing Spouse', definition: 'A spouse who is on title but not on the mortgage. Rules vary by state and program.', relatedTerms: ['qualification', 'va-loan'] },
  { slug: 'community-property', term: 'Community Property', definition: 'In some states, property acquired during marriage is owned equally by both spouses. Affects title and sometimes liability.', relatedTerms: ['deed', 'title'] },
  { slug: 'joint-tenancy', term: 'Joint Tenancy', definition: 'Ownership by two or more persons with right of survivorship. When one dies, the other(s) get the share.', relatedTerms: ['deed', 'title'] },
  { slug: 'tenancy-in-common', term: 'Tenancy in Common', definition: 'Ownership by two or more persons without right of survivorship. Each can sell or will their share.', relatedTerms: ['deed', 'title'] },
  { slug: 'homestead', term: 'Homestead', definition: 'Legal protection of a primary residence from certain creditors. Varies by state.', relatedTerms: ['primary-residence'] },
  { slug: 'loan-number', term: 'Loan Number', definition: 'The identifier the lender or servicer assigns to your mortgage. Used for payments and account inquiries.', relatedTerms: ['servicing'] },
  { slug: 'payoff-amount', term: 'Payoff Amount', definition: 'The total required to pay off the loan, including principal, interest to payoff date, and any fees.', relatedTerms: ['payoff-statement', 'refinance'] },
  { slug: 'principal-curtailment', term: 'Principal Curtailment', definition: 'An extra payment applied directly to principal to reduce the balance and total interest.', relatedTerms: ['paying-off-early', 'amortization'] },
  { slug: 'partial-payment', term: 'Partial Payment', definition: 'A payment less than the full amount due. Servicers may hold partial payments until full payment is received.', relatedTerms: ['servicing'] },
  { slug: 'late-fee', term: 'Late Fee', definition: 'A fee charged when a payment is received after the grace period.', relatedTerms: ['servicing'] },
  { slug: 'grace-period', term: 'Grace Period', definition: 'The number of days after the due date before a payment is considered late. Varies by lender.', relatedTerms: ['late-fee', 'servicing'] },
  { slug: 'delinquency', term: 'Delinquency', definition: 'Being past due on a payment. Serious delinquency is often 90+ days and can lead to foreclosure.', relatedGuides: [{ label: 'What Is Mortgage Delinquency', href: '/mortgage/what-is-mortgage-delinquency' }], relatedTerms: ['foreclosure', 'forbearance'] },
  { slug: 'default', term: 'Default', definition: 'Failure to meet the terms of the loan (e.g., non-payment). Can lead to foreclosure.', relatedGuides: [{ label: 'What Is Mortgage Default', href: '/mortgage/what-is-mortgage-default' }], relatedTerms: ['foreclosure', 'delinquency'] },
  { slug: 'loss-mitigation', term: 'Loss Mitigation', definition: 'Options to avoid foreclosure, such as loan modification, forbearance, or short sale.', relatedTerms: ['loan-modification', 'forbearance'] },
  { slug: 'deed-in-lieu', term: 'Deed in Lieu of Foreclosure', definition: 'Transferring the property to the lender to satisfy the loan and avoid foreclosure.', relatedTerms: ['foreclosure', 'short-sale'] },
  { slug: 'right-of-rescission', term: 'Right of Rescission', definition: 'The right to cancel certain loans (e.g., refinances on primary residence) within three business days. TILA requirement.', relatedTerms: ['tila', 'refinance'] },
  { slug: 'finance-charge', term: 'Finance Charge', definition: 'The total cost of credit, including interest and certain fees. Disclosed under TILA.', relatedTerms: ['tila', 'apr'] },
  { slug: 'amount-financed', term: 'Amount Financed', definition: 'The principal amount borrowed, used for TILA disclosures.', relatedTerms: ['tila', 'principal'] },
  { slug: 'total-of-payments', term: 'Total of Payments', definition: 'The sum of all payments you will make over the life of the loan if you pay as scheduled.', relatedTerms: ['amortization', 'tila'] },
  { slug: 'cooling-off-period', term: 'Cooling-Off Period', definition: 'Same as right of rescission — time to cancel the transaction.', relatedTerms: ['right-of-rescission'] },
  { slug: 'loan-estimate-expiration', term: 'Loan Estimate Expiration', definition: 'The date after which the Loan Estimate is no longer valid. Lenders must honor it for a set period if you proceed.', relatedTerms: ['loan-estimate'] },
  { slug: 'closing-disclosure-3-day', term: 'Closing Disclosure 3-Day Rule', definition: 'You must receive the Closing Disclosure at least three business days before closing to review.', relatedTerms: ['closing-disclosure', 'right-of-rescission'] },
  { slug: 'changed-circumstance', term: 'Changed Circumstance', definition: 'Events that may allow a lender to revise the Loan Estimate (e.g., change in your credit or loan terms).', relatedTerms: ['loan-estimate', 'closing-disclosure'] },
  { slug: 'tolerance', term: 'Tolerance (Closing Cost)', definition: 'Limits on how much certain closing costs can increase from the Loan Estimate. Zero tolerance for some fees.', relatedTerms: ['loan-estimate', 'closing-costs'] },
  { slug: 'zero-tolerance', term: 'Zero Tolerance', definition: 'Fees that cannot increase from Loan Estimate to Closing Disclosure (e.g., lender fees for services it chose).', relatedTerms: ['tolerance', 'closing-costs'] },
  { slug: '10-percent-tolerance', term: '10% Tolerance', definition: 'Certain fees can increase by no more than 10% in total from the Loan Estimate.', relatedTerms: ['tolerance', 'closing-costs'] },
  { slug: 'no-tolerance', term: 'No Tolerance', definition: 'Fees that can change without limit (e.g., prepaid items, services you choose).', relatedTerms: ['tolerance'] },
  { slug: 'intent-to-proceed', term: 'Intent to Proceed', definition: 'Your communication to the lender that you want to move forward. Required before the lender can charge fees (except credit report).', relatedTerms: ['loan-estimate'] },
  { slug: 'red-flag', term: 'Red Flag (Loan Estimate)', definition: 'Notices on the Loan Estimate that highlight key terms (e.g., rate increase on ARM, balloon payment).', relatedTerms: ['loan-estimate'] },
  { slug: 'section-a-b-c', term: 'Loan Estimate Section A B C', definition: 'Sections of the Loan Estimate: A (origination), B (services you cannot shop), C (services you can shop).', relatedTerms: ['loan-estimate', 'closing-costs'] },
  { slug: 'section-d-e', term: 'Closing Disclosure Section D E', definition: 'Sections for taxes and government fees (D) and prepaids and escrow (E).', relatedTerms: ['closing-disclosure'] },
  { slug: 'section-f-g', term: 'Closing Disclosure Section F G', definition: 'Section F: other costs (e.g., title); Section G: total loan costs and total other costs.', relatedTerms: ['closing-disclosure'] },
  { slug: 'lender-credits', term: 'Lender Credits', definition: 'Credits from the lender that reduce your closing costs, often in exchange for a higher rate.', relatedTerms: ['closing-costs', 'no-closing-cost-refinance'] },
  { slug: 'seller-credits', term: 'Seller Credits', definition: 'Same as seller concessions — the seller pays certain closing costs.', relatedTerms: ['seller-concessions'] },
  { slug: 'earnest-money-credit', term: 'Earnest Money Credit', definition: 'Applying your earnest money deposit toward the down payment or closing costs at closing.', relatedTerms: ['earnest-money', 'cash-to-close'] },
  { slug: 'loan-deposit', term: 'Loan Deposit', definition: 'Funds deposited by the borrower (e.g., earnest money) held until closing.', relatedTerms: ['earnest-money'] },
  { slug: 'wire-fraud', term: 'Wire Fraud', definition: 'Scams where criminals trick you into wiring closing funds to them. Verify wiring instructions in person or by known phone number.', relatedTerms: ['closing'] },
  { slug: 'dry-closing', term: 'Dry Closing', definition: 'A closing where documents are signed but funds are not yet disbursed. “Wet” closing means funds are disbursed at closing.', relatedTerms: ['closing'] },
  { slug: 'wet-closing', term: 'Wet Closing', definition: 'A closing where the loan is funded and disbursed at the same time as signing.', relatedTerms: ['closing', 'dry-closing'] },
  { slug: 'table-funding', term: 'Table Funding', definition: 'When a broker closes the loan in the lender’s name and the lender provides funds at the table.', relatedTerms: ['mortgage-broker', 'lender'] },
  { slug: 'wholesale-lender', term: 'Wholesale Lender', definition: 'A lender that works through brokers rather than directly with borrowers.', relatedTerms: ['mortgage-broker', 'retail-lender'] },
  { slug: 'retail-lender', term: 'Retail Lender', definition: 'A lender that originates loans directly to borrowers (e.g., bank or nonbank retail channel).', relatedTerms: ['wholesale-lender'] },
  { slug: 'correspondent-lender', term: 'Correspondent Lender', definition: 'A lender that funds loans with its own money and then sells them to another entity (e.g., Fannie Mae).', relatedTerms: ['lender', 'conforming-loan'] },
  { slug: 'warehouse-line', term: 'Warehouse Line', definition: 'A line of credit lenders use to fund mortgages before selling them to investors.', relatedTerms: ['lender'] },
  { slug: 'secondary-market', term: 'Secondary Market', definition: 'Where mortgages are sold (e.g., to Fannie Mae, Freddie Mac, or investors). Frees up lender capital for new loans.', relatedTerms: ['conforming-loan', 'fannie-mae', 'freddie-mac'] },
  { slug: 'fannie-mae', term: 'Fannie Mae', definition: 'Federal National Mortgage Association — a government-sponsored enterprise that buys and guarantees conforming mortgages.', relatedTerms: ['freddie-mac', 'conforming-loan', 'fhfa'] },
  { slug: 'freddie-mac', term: 'Freddie Mac', definition: 'Federal Home Loan Mortgage Corporation — a government-sponsored enterprise that buys and guarantees conforming mortgages.', relatedTerms: ['fannie-mae', 'conforming-loan', 'fhfa'] },
  { slug: 'fhfa', term: 'FHFA', definition: 'Federal Housing Finance Agency — regulator of Fannie Mae and Freddie Mac. Sets conforming loan limits.', relatedTerms: ['fannie-mae', 'freddie-mac', 'conforming-loan'] },
  { slug: 'gse', term: 'GSE (Government-Sponsored Enterprise)', definition: 'Fannie Mae and Freddie Mac. They have a federal charter but are not government agencies.', relatedTerms: ['fannie-mae', 'freddie-mac'] },
  { slug: 'gnma', term: 'Ginnie Mae', definition: 'Government National Mortgage Association — guarantees securities backed by FHA, VA, USDA, and other government loans.', relatedTerms: ['fha-loan', 'va-loan', 'usda-loan'] },
  { slug: 'hud', term: 'HUD', definition: 'U.S. Department of Housing and Urban Development — oversees FHA and housing programs.', relatedTerms: ['fha-loan', 'fha-mip'] },
  { slug: 'cfpb', term: 'CFPB', definition: 'Consumer Financial Protection Bureau — enforces consumer financial laws and issues mortgage rules (e.g., TILA, RESPA).', relatedTerms: ['tila', 'respa', 'loan-estimate'] },
  { slug: 'ability-to-repay', term: 'Ability to Repay (ATR) Rule', definition: 'Federal requirement that lenders make a reasonable determination that the borrower can repay the loan.', relatedTerms: ['atr', 'qualified-mortgage'] },
  { slug: 'qm-patch', term: 'QM Patch', definition: 'Former temporary provision that gave QM status to certain Fannie/Freddie loans. Expired; GSEs now use general QM or other standards.', relatedTerms: ['qualified-mortgage'] },
  { slug: 'general-qm', term: 'General QM', definition: 'Qualified Mortgage category based on the borrower’s APR vs the average prime offer rate (APOR).', relatedTerms: ['qualified-mortgage', 'atr'] },
  { slug: 'apor', term: 'APOR (Average Prime Offer Rate)', definition: 'A benchmark rate published by the CFPB used for QM and other rules.', relatedTerms: ['general-qm', 'qualified-mortgage'] },
  { slug: 'points-and-fees-cap', term: 'Points and Fees Cap', definition: 'QM loans generally cannot exceed a cap on points and fees as a percentage of the loan amount.', relatedTerms: ['qualified-mortgage', 'closing-costs'] },
  { slug: 'high-cost-mortgage', term: 'High-Cost Mortgage', definition: 'A loan that exceeds certain rate or fee thresholds and triggers additional consumer protections.', relatedTerms: ['tila', 'hoepa'] },
  { slug: 'hoepa', term: 'HOEPA', definition: 'Home Ownership and Equity Protection Act — additional rules for high-cost mortgages.', relatedTerms: ['high-cost-mortgage', 'tila'] },
  { slug: 'manufactured-housing', term: 'Manufactured Housing', definition: 'Homes built in a factory to HUD code. May be titled as personal or real property depending on state.', relatedTerms: ['manufactured-home'] },
  { slug: 'chattel', term: 'Chattel', definition: 'Personal property. A chattel loan is used when the manufactured home is not permanently affixed and is titled as personal property.', relatedTerms: ['manufactured-home'] },
  { slug: 'modular-home', term: 'Modular Home', definition: 'A factory-built home assembled on site and typically treated like site-built for financing.', relatedTerms: ['manufactured-home', 'construction-loan'] },
  { slug: 'tiny-home', term: 'Tiny Home', definition: 'A very small dwelling. Financing depends on whether it’s on a foundation and meets code (e.g., conventional, FHA) or is on wheels.', relatedTerms: ['manufactured-home'] },
  { slug: 'co-borrower', term: 'Co-Borrower', definition: 'A person who applies for the loan with you and is equally responsible for repayment. Income and debt are included.', relatedTerms: ['qualification', 'non-borrowing-spouse'] },
  { slug: 'cosigner', term: 'Co-Signer', definition: 'Someone who signs the loan and is responsible if you don’t pay. May or may not be on title.', relatedTerms: ['co-borrower', 'qualification'] },
  { slug: 'non-occupant-co-borrower', term: 'Non-Occupant Co-Borrower', definition: 'A co-borrower who will not live in the property. Allowed in some programs (e.g., FHA) with restrictions.', relatedTerms: ['co-borrower', 'fha-loan'] },
  { slug: 'asset-depletion', term: 'Asset Depletion', definition: 'Using assets (e.g., investments) to qualify by “depleting” them over the loan term as hypothetical income.', relatedTerms: ['qualification', 'non-qm'] },
  { slug: 'bank-statement-program', term: 'Bank Statement Program', definition: 'A program that uses bank statements to verify income instead of tax returns. Common for self-employed.', relatedTerms: ['bank-statement-loan', 'self-employed'] },
  { slug: '1099-income', term: '1099 Income', definition: 'Income reported on 1099 forms (e.g., freelance). Lenders may average or use other methods to qualify 1099 income.', relatedTerms: ['self-employed', 'qualification'] },
  { slug: 'w2-income', term: 'W-2 Income', definition: 'Wage income reported on a W-2. Easiest for lenders to verify and use for qualification.', relatedTerms: ['qualification', 'employment'] },
  { slug: 'overtime-income', term: 'Overtime and Bonus Income', definition: 'Lenders may count overtime and bonus income if it’s likely to continue. Often require a two-year history.', relatedTerms: ['qualification', 'income'] },
  { slug: 'reserves', term: 'Reserves', definition: 'Liquid assets left after closing. Expressed in months of PITI. Higher reserves can help approval and pricing.', relatedTerms: ['qualification', 'closing-costs'] },
  { slug: 'gift-letter', term: 'Gift Letter', definition: 'A signed letter stating that funds given to the borrower are a gift and do not need to be repaid.', relatedGuides: [{ label: 'Gift Funds for Down Payment', href: '/mortgage/gift-funds-down-payment' }], relatedTerms: ['gift-funds', 'down-payment'] },
  { slug: 'source-of-funds', term: 'Source of Funds', definition: 'Documentation showing where the money for down payment and closing costs came from (e.g., savings, gift, sale of asset).', relatedTerms: ['gift-funds', 'underwriting'] },
  { slug: 'earnest-money-refund', term: 'Earnest Money Refund', definition: 'Return of earnest money if the contract is terminated under allowed circumstances (e.g., financing contingency).', relatedTerms: ['earnest-money', 'contingency'] },
  { slug: 'loan-denial', term: 'Loan Denial', definition: 'The lender’s decision not to approve the loan. You have the right to know the reason and to dispute errors.', relatedGuides: [{ label: 'Mortgage Denial and What to Do', href: '/mortgage/mortgage-denial' }], relatedTerms: ['underwriting', 'credit-report'] },
  { slug: 'adverse-action', term: 'Adverse Action', definition: 'A notice required when a loan is denied or offered on less favorable terms, explaining the reason (e.g., credit score).', relatedTerms: ['loan-denial', 'credit-report'] },
  { slug: 'counter-offer', term: 'Counter-Offer', definition: 'A loan offer with different terms (e.g., higher rate) when the initial application does not qualify for the best terms.', relatedTerms: ['underwriting', 'qualification'] },
  { slug: 'conditional-approval', term: 'Conditional Approval', definition: 'Approval subject to satisfying conditions (e.g., providing documents, clearing title).', relatedTerms: ['clear-to-close', 'underwriting'] },
  { slug: 'prior-to-document', term: 'Prior to Doc (PTD)', definition: 'Conditions that must be met before the lender will prepare closing documents.', relatedTerms: ['conditional-approval', 'underwriting'] },
  { slug: 'prior-to-funding', term: 'Prior to Funding (PTF)', definition: 'Conditions that must be met before the lender will fund the loan.', relatedTerms: ['conditional-approval', 'clear-to-close'] },
  { slug: 'flip', term: 'Flipping (Property)', definition: 'Buying a property and quickly reselling for profit. Lenders may have rules on recent resales (e.g., FHA anti-flipping).', relatedTerms: ['investment-property', 'fha-loan'] },
  { slug: 'seasoning', term: 'Seasoning', definition: 'The time a borrower has owned a property or had a loan. Refinance and some programs require seasoning (e.g., six months).', relatedTerms: ['refinance', 'cash-out-refinance'] },
  { slug: 'title-commitment', term: 'Title Commitment', definition: 'A preliminary report from the title company listing requirements to issue the policy and any liens or defects.', relatedTerms: ['title-insurance', 'title-search'] },
  { slug: 'title-policy', term: 'Title Policy', definition: 'The insurance policy that protects against title defects. Lender’s policy is usually required; owner’s policy is optional.', relatedTerms: ['title-insurance', 'closing'] },
  { slug: 'lender-title-policy', term: "Lender's Title Policy", definition: 'Protects the lender’s interest in the property. Usually required and often paid by the borrower.', relatedTerms: ['title-insurance'] },
  { slug: 'owner-title-policy', term: "Owner's Title Policy", definition: 'Protects the homeowner’s equity against title defects. Optional in many states but recommended.', relatedTerms: ['title-insurance'] },
  { slug: 'endorsement', term: 'Title Endorsement', definition: 'An addition to a title policy that expands or clarifies coverage.', relatedTerms: ['title-policy'] },
  { slug: 'survey', term: 'Survey', definition: 'A map showing property boundaries and improvements. Lenders may require it for certain loans.', relatedTerms: ['closing-costs', 'title'] },
  { slug: 'hazard-insurance', term: 'Hazard Insurance', definition: 'Insurance that covers physical damage to the property (fire, wind, etc.). Often used interchangeably with homeowner’s insurance.', relatedTerms: ['homeowners-insurance', 'piti'] },
  { slug: 'flood-insurance', term: 'Flood Insurance', definition: 'Coverage for flood damage. Required in FEMA flood zones; often available through NFIP or private carriers.', relatedTerms: ['flood-certificate', 'closing-costs'] },
  { slug: 'umbrella-insurance', term: 'Umbrella Insurance', definition: 'Liability coverage above your auto and homeowner policies. Not required for the mortgage but can protect assets.', relatedTerms: ['homeowners-insurance'] },
  { slug: 'loss-payable', term: 'Loss Payable Clause', definition: 'A clause in an insurance policy that pays the lender if the property is damaged or destroyed.', relatedTerms: ['hazard-insurance', 'lender'] },
  { slug: 'mortgagee-clause', term: 'Mortgagee Clause', definition: 'The clause in an insurance policy that names the lender as payee for claims. Lenders require this.', relatedTerms: ['hazard-insurance'] },
];

/** All glossary entries. */
export function getAllGlossaryEntries(): GlossaryEntry[] {
  return glossary;
}

/** Get one entry by slug. */
export function getGlossaryEntryBySlug(slug: string): GlossaryEntry | undefined {
  return glossary.find((e) => e.slug === slug);
}

/** All slugs for static generation. */
export function getAllGlossarySlugs(): string[] {
  return glossary.map((e) => e.slug);
}

/** Entries for a given letter (A–Z). */
export function getGlossaryEntriesByLetter(letter: string): GlossaryEntry[] {
  const upper = letter.toUpperCase();
  return glossary.filter((e) => e.term.toUpperCase().startsWith(upper));
}
